import tkinter as tk
from tkinter import ttk, scrolledtext, messagebox
import threading
import logging
import re
import json
import os
import warnings
import sys
import time
import torch
import zlib
import base64
from transformers import AutoTokenizer, AutoModelForCausalLM

os.environ["HF_HUB_DISABLE_SYMLINKS_WARNING"] = "1"
os.environ["TRANSFORMERS_VERBOSITY"] = "error"

logging.getLogger("huggingface_hub").setLevel(logging.ERROR)
warnings.filterwarnings("ignore", category=UserWarning, module="huggingface_hub")

MODEL_NAME = "p1atdev/dart-v2-moe-sft"

TOP_K = 20
TOP_P = 1.0
TEMPERATURE = 1.0

CHARTAGS_DATA = ""
ARTAGS_DATA = ""
GENTAGS_DATA = ""
METATAGS_DATA = ""

FIELDS =[
    ("Artist:", "artist_entry", "", False, True),
    ("Copyright:", "copyright_entry", "vocaloid", False, True),
    ("Character:", "character_entry", "hatsune miku", False, True),
    ("General:", "general_entry", "1girl", False, True),
    ("Meta:", "meta_entry", "", False, True),
    ("Banned Tags:", "banned_entry", "", False, False), # Added banned tags
    ("Rating:", "rating_combo", ["general", "sensitive", "questionable", "explicit"], True, False),
    ("Aspect Ratio:", "aspect_combo", ["tall", "square", "wide"], True, False),
    ("Length:", "length_combo", ["short", "medium", "long", "very_long"], True, False),
]

COMBO_DEFAULTS = {
    "rating_combo": "general",
    "aspect_combo": "tall",
    "length_combo": "long",
}

class DanbooruTagGeneratorApp:
    def __init__(self, root):
        self.root = root
        self.root.title("Danbooru Tags Generator")
        self.root.geometry("500x630") # Increased height slightly for new fields
        self.root.resizable(False, False)
        
        icon_path = os.path.join(getattr(sys, '_MEIPASS', os.path.dirname(os.path.abspath(__file__))), "icon.ico")
        if os.path.exists(icon_path):
            try:
                self.root.iconbitmap(icon_path)
            except:
                pass
        
        self.model = None
        self.tokenizer = None
        self.device = "cpu"
        torch.set_num_threads(os.cpu_count() or 4)
        
        self.tags_db_loaded = False
        self.copyrights_list = []
        self.characters_list = []
        self.artists_list = []
        self.general_tags_list = []
        self.meta_tags_list = []
        self.char_to_copy_map = {}
        self.copy_to_chars_map = {}
        
        self.create_widgets()
        self.root.bind("<Return>", self.on_generate_click)
        self.root.bind("<Control-c>", self._on_ctrl_c)
        self.root.bind("<Control-C>", self._on_ctrl_c)
        
        threading.Thread(target=self.load_model, daemon=True).start()
        threading.Thread(target=self.load_tags_database, daemon=True).start()

    def load_tags_database(self):
        def decode_embedded(encoded_str):
            if not encoded_str:
                return None
            try:
                compressed_data = base64.b64decode(encoded_str)
                decompressed_data = zlib.decompress(compressed_data)
                return json.loads(decompressed_data.decode('utf-8'))
            except Exception as e:
                print(f"Decode Error: {e}")
                return None

        data = decode_embedded(CHARTAGS_DATA)
        if data:
            self.copyrights_list = [c["name"] for c in data.get("copyrights", [])]
            self.characters_list = [c["name"] for c in data.get("characters", [])]
            copy_id_to_name = {c["id"]: c["name"] for c in data.get("copyrights", [])}
            for char in data.get("characters", []):
                char_name, copy_id = char["name"], char["copyright_id"]
                if copy_id != -1 and copy_id in copy_id_to_name:
                    copy_name = copy_id_to_name[copy_id]
                    self.char_to_copy_map[char_name] = copy_name
                    self.copy_to_chars_map.setdefault(copy_name, []).append(char_name)
            self.tags_db_loaded = True

        art_data = decode_embedded(ARTAGS_DATA)
        if art_data: 
            self.artists_list = [t["name"] for t in art_data]
            
        gen_data = decode_embedded(GENTAGS_DATA)
        if gen_data: 
            self.general_tags_list = [t["name"] for t in gen_data]

        meta_data = decode_embedded(METATAGS_DATA)
        if meta_data:
            self.meta_tags_list = [t["name"] for t in meta_data]

        if self.tags_db_loaded:
            self.root.after(0, lambda: self.status_var.set("Tag database loaded."))

    def create_widgets(self):
        main = ttk.Frame(self.root, padding=10)
        main.pack(fill=tk.BOTH, expand=True)

        input_frame = ttk.LabelFrame(main, text=" Prompt Settings ", padding="10 5 10 5")
        input_frame.pack(fill=tk.X, pady=(0, 10))
        input_frame.columnconfigure(1, weight=1)
        input_frame.columnconfigure(2, weight=0)

        for i, (label, attr, default, is_combo, has_browser) in enumerate(FIELDS):
            ttk.Label(input_frame, text=label).grid(row=i, column=0, sticky=tk.W, pady=2)
            if is_combo:
                widget = ttk.Combobox(input_frame, values=default, state="readonly")
                widget.set(COMBO_DEFAULTS.get(attr, default[0]))
                widget.grid(row=i, column=1, columnspan=2, sticky=(tk.W, tk.E), pady=2, padx=(5, 0))
            else:
                widget = ttk.Entry(input_frame)
                widget.insert(0, default)
                if has_browser:
                    widget.grid(row=i, column=1, sticky=(tk.W, tk.E), pady=2, padx=(5, 5))
                    btn = ttk.Button(input_frame, text="...", width=3, 
                                     command=lambda m=attr.split('_')[0]: self.open_browser(m))
                    btn.grid(row=i, column=2, sticky=tk.E, pady=2)
                else:
                    widget.grid(row=i, column=1, columnspan=2, sticky=(tk.W, tk.E), pady=2, padx=(5, 0))
                    
            setattr(self, attr, widget)

        self.generate_btn = ttk.Button(main, text="Loading Model...", state=tk.DISABLED, command=self.on_generate_click)
        self.generate_btn.pack(fill=tk.X, pady=10)

        output_frame = ttk.LabelFrame(main, text=" Generated Tags ", padding="10 5 10 5")
        output_frame.pack(fill=tk.BOTH, expand=True, pady=(0, 10))
        self.output_text = scrolledtext.ScrolledText(output_frame, wrap=tk.WORD, height=4, font=("Consolas", 10))
        self.output_text.pack(fill=tk.BOTH, expand=True)

        bottom = ttk.Frame(main)
        bottom.pack(fill=tk.X)
        self.copy_btn = ttk.Button(bottom, text="Copy to Clipboard (Ctrl+C)", command=self.copy_to_clipboard, state=tk.DISABLED)
        self.copy_btn.pack(side=tk.LEFT, fill=tk.X, expand=True, pady=5)

        self.status_var = tk.StringVar(value="Initializing...")
        ttk.Label(main, textvariable=self.status_var, foreground="gray", font=("Segoe UI", 8)).pack(side=tk.BOTTOM, anchor=tk.E)

    def open_browser(self, mode):
        if mode in ["character", "copyright"] and not self.tags_db_loaded:
            messagebox.showwarning("Database Missing", "chartags.json not found or still loading.")
            return
        if mode == "artist" and not self.artists_list:
            messagebox.showwarning("Database Missing", "artags.json not found or still loading.")
            return
        if mode == "general" and not self.general_tags_list:
            messagebox.showwarning("Database Missing", "gentags.json not found or still loading.")
            return
        if mode == "meta" and not self.meta_tags_list:
            messagebox.showwarning("Database Missing", "metatags_data not found or still loading.")
            return

        top = tk.Toplevel(self.root)
        top.title(f"Select {mode.capitalize()}")
        
        w, h = 400, 450
        x = self.root.winfo_x() + (self.root.winfo_width() // 2) - (w // 2)
        y = self.root.winfo_y() + (self.root.winfo_height() // 2) - (h // 2)
        top.geometry(f"{w}x{h}+{x}+{y}")
        
        top.transient(self.root)
        top.grab_set()
        top.bind("<Escape>", lambda e: top.destroy())

        filter_frame = ttk.Frame(top)
        filter_frame.pack(fill=tk.X, padx=10, pady=(10, 5))

        filter_var = tk.StringVar()
        filter_entry = ttk.Entry(filter_frame, textvariable=filter_var)
        filter_entry.pack(side=tk.LEFT, fill=tk.X, expand=True)

        prefix_var = tk.BooleanVar(value=False)
        if mode == "artist":
            prefix_cb = ttk.Checkbutton(filter_frame, text="Prefix @?", variable=prefix_var)
            prefix_cb.pack(side=tk.RIGHT, padx=(5, 0))

        list_frame = ttk.Frame(top)
        list_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=(0, 10))

        listbox = tk.Listbox(list_frame, font=("Segoe UI", 10))
        scrollbar = ttk.Scrollbar(list_frame, command=listbox.yview)
        listbox.config(yscrollcommand=scrollbar.set)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        listbox.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        if mode == "copyright":
            current_char = self.character_entry.get().strip()
            if current_char in self.char_to_copy_map:
                base_list = [self.char_to_copy_map[current_char]]
            else:
                base_list = self.copyrights_list
        elif mode == "character":
            current_copy = self.copyright_entry.get().strip()
            if current_copy in self.copy_to_chars_map:
                base_list = self.copy_to_chars_map[current_copy]
            else:
                base_list = self.characters_list
        elif mode == "artist":
            base_list = self.artists_list
        elif mode == "general":
            base_list = self.general_tags_list
        elif mode == "meta":
            base_list = self.meta_tags_list

        def update_list(*args):
            q = filter_var.get().lower().replace(" ", "_")
            listbox.delete(0, tk.END)
            count = 0
            for item in base_list:
                if q in item.lower():
                    listbox.insert(tk.END, item)
                    count += 1
                    if count >= 1000:
                        break

        filter_var.trace_add("write", update_list)
        update_list()

        def on_select(event=None):
            selection = listbox.curselection()
            if not selection:
                if listbox.size() > 0:
                    selected_item = listbox.get(0)
                else:
                    return
            else:
                selected_item = listbox.get(selection[0])
            
            if mode in ["artist", "general", "meta"]:
                widget = getattr(self, f"{mode}_entry")
                current = widget.get().strip()
                if mode == "artist" and prefix_var.get():
                    selected_item = "@" + selected_item
                current = current.rstrip(',')
                new_text = f"{current}, {selected_item}" if current else selected_item
                widget.delete(0, tk.END)
                widget.insert(0, new_text)
                filter_var.set("")
                filter_entry.focus_set()
            else:
                if mode == 'copyright':
                    self.copyright_entry.delete(0, tk.END)
                    self.copyright_entry.insert(0, selected_item)
                else:
                    self.character_entry.delete(0, tk.END)
                    self.character_entry.insert(0, selected_item)
                    copy_name = self.char_to_copy_map.get(selected_item)
                    if copy_name:
                        self.copyright_entry.delete(0, tk.END)
                        self.copyright_entry.insert(0, copy_name)
                top.destroy()

        listbox.bind("<Double-Button-1>", on_select)
        listbox.bind("<Return>", on_select)
        filter_entry.bind("<Return>", on_select)
        filter_entry.focus_set()

    def load_model(self):
        try:
            self.tokenizer = AutoTokenizer.from_pretrained(MODEL_NAME)
            self.model = AutoModelForCausalLM.from_pretrained(MODEL_NAME, dtype=torch.bfloat16)
            self.model.to(self.device)
            self.root.after(0, self.on_model_loaded)
        except Exception as e:
            self.root.after(0, self.on_model_error, str(e))

    def on_model_loaded(self):
        self.generate_btn.config(text="Generate Tags (Enter)", state=tk.NORMAL)
        self.status_var.set("Ready.")

    def on_model_error(self, error_msg):
        self.status_var.set("Error loading model.")
        messagebox.showerror("Model Load Error", f"Failed to load model:\n{error_msg}")

    def _on_ctrl_c(self, event):
        focused = self.root.focus_get()
        if focused:
            if isinstance(focused, (tk.Text, scrolledtext.ScrolledText)):
                try:
                    if focused.tag_ranges(tk.SEL):
                        return
                except tk.TclError:
                    pass
            elif isinstance(focused, (tk.Entry, ttk.Entry, ttk.Combobox)):
                try:
                    if focused.select_present():
                        return
                except tk.TclError:
                    pass
        self.copy_to_clipboard()
        return "break"

    def on_generate_click(self, event=None):
        if str(self.generate_btn["state"]) == tk.DISABLED:
            return
        self.generate_btn.config(state=tk.DISABLED)
        self.copy_btn.config(state=tk.DISABLED)
        self.status_var.set("Generating tags...")
        self.output_text.delete(1.0, tk.END)
        threading.Thread(target=self.generate_tags, daemon=True).start()

    def generate_tags(self):
        try:
            start_time = time.perf_counter()
            artist_txt    = re.sub(r"([()])", r"\\\1", self.artist_entry.get().strip())
            copyright_txt = self.copyright_entry.get().strip().replace("_", " ")
            character_txt = self.character_entry.get().strip().replace("_", " ")
            general_txt   = self.general_entry.get().strip().replace("_", " ")
            meta_txt      = re.sub(r"([()])", r"\\\1", self.meta_entry.get().strip())
            banned_txt    = self.banned_entry.get().strip()
            
            prompt = f"<|bos|>"
            if copyright_txt: prompt += f"<copyright>{copyright_txt}</copyright>"
            if character_txt: prompt += f"<character>{character_txt}</character>"
            
            # Concatenate these tags instead of feeding them to the model
            prompt += f"<|rating:{self.rating_combo.get()}|><|aspect_ratio:{self.aspect_combo.get()}|><|length:{self.length_combo.get()}|>"
            prompt += f"<general>{general_txt}<|identity:none|><|input_end|>"

            inputs = self.tokenizer(prompt, return_tensors="pt").input_ids.to(self.device)
            
            # Setup Banned Words / Suppression List
            bad_words_ids = None
            if banned_txt:
                bad_words_ids = []
                for tag in banned_txt.split(","):
                    tag = tag.strip()
                    if tag:
                        # Extract exact sequence of IDs for the banned tag
                        ids = self.tokenizer(tag, add_special_tokens=False).input_ids
                        if ids:
                            bad_words_ids.append(ids)

            with torch.no_grad():
                outputs = self.model.generate(
                    inputs, 
                    do_sample=True, 
                    temperature=TEMPERATURE, 
                    top_p=TOP_P, 
                    top_k=TOP_K, 
                    max_new_tokens=128,
                    bad_words_ids=bad_words_ids if bad_words_ids else None
                )

            tags = [re.sub(r"([()])", r"\\\1", t.strip()) for t in self.tokenizer.batch_decode(outputs[0].unsqueeze(-1), skip_special_tokens=True) if t.strip() and "text" not in t.lower()]
            
            res = ", ".join(tags)
            if artist_txt: res = f"{artist_txt}, {res}"
            if meta_txt: res = f"{res}, {meta_txt}"
            
            ms = int((time.perf_counter() - start_time) * 1000)
            self.root.after(0, self.on_generation_complete, res, ms)
        except Exception as e:
            self.root.after(0, self.on_generation_error, str(e))

    def on_generation_complete(self, result, ms):
        self.output_text.delete(1.0, tk.END)
        self.output_text.insert(tk.END, result)
        self.generate_btn.config(state=tk.NORMAL)
        self.copy_btn.config(state=tk.NORMAL)
        self.status_var.set(f"Generated in {ms} ms.")

    def on_generation_error(self, error_msg):
        self.generate_btn.config(state=tk.NORMAL)
        self.status_var.set("Error during generation.")
        messagebox.showerror("Generation Error", f"An error occurred:\n{error_msg}")

    def copy_to_clipboard(self):
        text = self.output_text.get(1.0, tk.END).strip()
        if text:
            self.root.clipboard_clear()
            self.root.clipboard_append(text)
            self.root.update()
            self.status_var.set("Copied to clipboard.")

if __name__ == "__main__":
    root = tk.Tk()
    DanbooruTagGeneratorApp(root)
    root.mainloop()